 96→	async findMostPopularByCategories({
 97→		categoryIds,
 98→		limit = 5,
 99→		excludeIds,
100→	}: {
101→		categoryIds: number[];
102→		limit?: number;
103→		excludeIds?: number[];
104→	}): Promise<IStyleBase[]> {
105→		try {
106→			const allResults: IStyleBase[] = [];
107→
108→			for (const categoryId of categoryIds) {
109→				let query = this.knexRead<BaseStyleDto>(this.tableName)
110→					.where('primary_category_id', categoryId)
111→					.whereNull('deleted_at');
112→
113→				if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
114→					query = query
115→						.whereNotNull('primary_category_id')
116→						.whereNotIn(
117→							'primary_category_id',
118→							FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
119→						);
120→				}
121→
122→				if (excludeIds?.length) {
123→					query = query.whereNotIn('style_id', excludeIds);
124→				}
125→
126→				const styles = await query.orderBy('purchases_count', 'desc').limit(limit);
127→
128→				const results = styles.map((style) => ({
129→					// eslint-disable-next-line
130→					...style,
131→					categories_ids:
132→						typeof style.categories_ids === 'string'
133→							? (JSON.parse(style.categories_ids) as number[])
134→							: style.categories_ids,
135→					categories_with_parents_ids:
136→						typeof style.categories_with_parents_ids === 'string'
137→							? (JSON.parse(style.categories_with_parents_ids) as number[])
138→							: style.categories_with_parents_ids,
139→				}));
140→
141→				const mappedResults = await Promise.all(
142→					results.map(async (result) => {
143→						const parsedData = this.parseStyleData(result as unknown as IStyleBase);
144→						const dto = plainToInstance(BaseStyleDto, parsedData);
145→						const errors = await validate(dto);
146→						if (errors.length > 0) {
147→							this.logger.error(
148→								`Validation failed for style data: ${this.formatValidationErrors(errors)}`,
149→							);
150→							throw new Error(
151→								`Validation failed: ${this.formatValidationErrors(errors)}`,
152→							);
153→						}
154→						return parsedData;
155→					}),
156→				);
157→				allResults.push(...mappedResults);
158→			}
159→
160→			this.logger.debug(
161→				`Found ${allResults.length} popular styles for categories ${categoryIds.join(', ')}`,
162→			);
163→			return allResults;
164→		} catch (error) {
165→			this.logger.error(
166→				`Failed to find popular styles for categories ${categoryIds.join(', ')}: ${(error as Error).message}`,
167→			);
168→			throw error;
169→		}
170→	}
