387→	async upsertStyle({
388→		data,
389→	}: {
390→		data: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
391→	}): Promise<IStyleBase> {
392→		try {
393→			const dto = plainToInstance(BaseStyleDto, data);
394→			const errors = await validate(dto, { skipMissingProperties: true });
395→
396→			if (errors.length > 0) {
397→				this.logger.error(
398→					`Validation failed for style data: ${this.formatValidationErrors(errors)}`,
399→				);
400→				throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
401→			}
402→
403→			const upsertedStyle: IStyleBase = await this.knexWrite.transaction(async (trx) => {
404→				const existing = await trx<IStyleBase>(this.tableName)
405→					.where({ style_id: data.style_id })
406→					.whereNull('deleted_at')
407→					.first();
408→
409→				if (existing) {
410→					const updateData: Record<string, unknown> = {
411→						updated_at: trx.fn.now(),
412→					};
413→
414→					Object.keys(data).forEach((key) => {
415→						if (key !== 'style_id') {
416→							if (
417→								key === 'categories_ids' ||
418→								key === 'categories_with_parents_ids' ||
419→								key === 'broad_category_names' ||
420→								key === 'sub_category_names' ||
421→								key === 'brand' ||
422→								key === 'sizes'
423→							) {
424→								updateData[key] = JSON.stringify(data[key as keyof typeof data] ?? []);
425→							} else {
426→								updateData[key] = data[key as keyof typeof data];
427→							}
428→						}
429→					});
430→
431→					await trx(this.tableName)
432→						.where({ style_id: data.style_id })
433→						.whereNull('deleted_at')
434→						.update(updateData);
435→				} else {
436→					const _id = randomUUID();
437→					const insertData: Record<string, unknown> = {
438→						_id,
439→						...data,
440→						style_id: data.style_id,
441→						primary_category_id: data.primary_category_id ?? null,
442→						root_category_id: data.root_category_id ?? null,
443→						purchases_count: data.purchases_count ?? 0,
444→						is_active: data.is_active ?? true,
445→						categories_ids: JSON.stringify(data.categories_ids ?? []),
446→						categories_with_parents_ids: JSON.stringify(
447→							data.categories_with_parents_ids ?? [],
448→						),
449→						broad_category_names: JSON.stringify(data.broad_category_names ?? []),
450→						sub_category_names: JSON.stringify(data.sub_category_names ?? []),
451→						brand: JSON.stringify(data.brand ?? []),
452→						sizes: JSON.stringify(data.sizes ?? []),
453→						created_at: trx.fn.now(),
454→						updated_at: trx.fn.now(),
455→					};
456→
457→					await trx(this.tableName).insert(insertData);
458→				}
459→
460→				const result = await trx<IStyleBase>(this.tableName)
461→					.where({ style_id: data.style_id })
462→					.whereNull('deleted_at')
463→					.first();
464→
465→				if (!result) {
466→					throw new Error(`Failed to upsert style with style ID ${data.style_id}`);
467→				}
468→
469→				return result;
470→			});
471→
472→			this.logger.debug(`Upserted style with style ID ${data.style_id}`);
473→			const plainData = instanceToPlain<BaseStyleDto>(upsertedStyle) as IStyleBase;
474→
475→			try {
476→				await this.stylesMvModel.refreshForStyle({ styleId: data.style_id });
477→			} catch (mvError: unknown) {
478→				const err = mvError instanceof Error ? mvError : new Error(String(mvError));
479→				this.logger.warn(
480→					`Failed to refresh MV for style ${data.style_id}: ${err.message}. Style data was saved successfully.`,
481→				);
482→				rollbar.error(err, { styleId: data.style_id, context: 'upsertStyle MV refresh' });
483→			}
484→
485→			return this.parseStyleData(plainData);
486→		} catch (error: unknown) {
487→			const err = error instanceof Error ? error : new Error(String(error));
488→			this.logger.error(
489→				`Failed to upsert style with style ID ${data.style_id}: ${err.message}`,
490→			);
491→			throw err;
492→		}
493→	}
