async update({
  styleId,
  colorId,
  data,
}: {
  styleId: IStyleColorBase['style_id'];
  colorId: number;
  data: IStyleColorUpdate;
}): Promise<IStyleColorBase | null> {
  // 1. VALIDATE INPUT using plainToInstance + validate
  const dto = plainToInstance(UpdateStyleColorDto, data);
  const errors = await validate(dto);

  // 2. CHECK VALIDATION ERRORS before proceeding
  if (errors.length > 0) {
    this.logger.error(
      `Validation failed for style update data: ${this.formatValidationErrors({ errors })}`,
    );
    throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
  }

  try {
    // 3. WRITE TO DB within transaction only after validation passes
    const res = await this.knexWrite.transaction(async (trx) => {
      await trx(this.tableName)
        .where({
          style_id: styleId,
          color_id: colorId,
        })
        .whereNull('deleted_at')
        .update({ ...data, updated_at: trx.fn.now() });

      return await trx<IStyleColorBase>(this.tableName)
        .where({
          style_id: styleId,
          color_id: colorId,
        })
        .whereNull('deleted_at')
        .orderBy('created_at', 'desc')
        .first();
    });

    if (!res) {
      this.logger.warn(`No style found for styleId ${styleId} and colorId ${colorId}`);
      return null;
    }

    this.logger.debug(`Updated style for styleId ${styleId} and colorId ${colorId}`);
    return this.parseStyleColorData(
      instanceToPlain<BaseStyleColorDto>(res) as IStyleColorBase,
    );
  } catch (error: unknown) {
    const err = error instanceof Error ? error : new Error(String(error));
    this.logger.error(
      `Failed to update style for styleId ${styleId} and colorId ${colorId}: ${err.message}`,
    );
    throw err;
  }
}
