    if (!res) {
      this.logger.warn(`No styles condensed_features found for styleId ${styleId}`);
      return null;
    }

    this.logger.debug(`Updated styles condensed_features for styleId ${styleId}`);

    // 6. VALIDATE RESULT before returning
    const resultDto = plainToInstance(BaseCondensedFeaturesDto, res);
    const resultErrors = await validate(resultDto);

    if (resultErrors.length > 0) {
      this.logger.error(
        `Validation failed for condensed features data: ${this.formatValidationErrors(resultErrors)}`,
      );
      throw new Error(`Validation failed: ${this.formatValidationErrors(resultErrors)}`);
    }

    return instanceToPlain<BaseCondensedFeaturesDto>(res) as ICondensedFeaturesBase;
  } catch (error) {
    this.logger.error(
      `Failed to update style condensed_features for styleId ${styleId}: ${(error as Error).message}`,
    );
    throw error;
  }
}
```

---

## Validation Pattern Summary

All update methods follow this consistent pattern:

1. **Create DTO instance** from input data: `plainToInstance(UpdateDto, data)`
2. **Validate DTO** using decorators: `validate(dto)`
3. **Check for errors** and throw early if validation fails
4. **Write to DB** within a transaction **only after validation passes**
5. **Parse/transform result** (e.g., `instanceToPlain`)
6. **Optional**: Validate result before returning (Example 3)

**Key Imports:**
```typescript
import { plainToInstance, instanceToPlain } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
```

**Error Formatting Helper:**
```typescript
private formatValidationErrors(errors: ValidationError[]): string {
  return errors
    .map(
      (error) =>
        `${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
    )
    .join('; ');
}
```

This ensures **zero invalid data reaches the database** - validation is a guard clause before any write operations occur.
